import { parseServerFormsValue } from '../../../models/server/forms/value.js';
import { serverSubmitItemCommunityActionRequestSchema } from '../../../schemas/server/items/community/submitItemCommunityActionRequest.js';
import { parse } from '../../../utils/json.js';
import { handleError } from '../../error.js';
export const createServerSubmitItemCommunityActionRouteHandler = (group) => async ({ req, res, localize, ctx }) => {
    if (!group.community.submitHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, serverSubmitItemCommunityActionRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    const value = parseServerFormsValue(Object.fromEntries(new URLSearchParams(request.values)), group.community.actions);
    if (!value) {
        res.status(400).end();
        return;
    }
    const response = await group.community.submitHandler({ ...ctx, itemName, value });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
